sql:
SELECT COUNT(*) 
FROM diaries 
WHERE language = 'English';

SELECT title
FROM diaries
WHERE status = 'active';

SELECT COUNT(entry_id) AS calm_entries_count
FROM entries
WHERE mood = 'calm';

SELECT author, COUNT(diary_id) AS diary_count
FROM diaries
GROUP BY author;

SELECT AVG(mood) AS average_mood
FROM entries
WHERE diary_id = (SELECT diary_id FROM diaries WHERE title = 'AWD0003hif');

SELECT strftime('%s', MAX(access_date)) AS most_recent_access
FROM access_logs
WHERE user_id = 0;

SELECT entry_date
FROM entries
ORDER BY entry_date;

SELECT diary_id, title, start_date
FROM diaries
ORDER BY start_date DESC;

SELECT title
FROM diaries
WHERE diary_id = 1;
